//====================================================
// VE.Direct Parser (ASCII + HEX)
//====================================================

let lines = String(msg.payload).split(/\r?\n/);
// GET readings
const REGISTERS = {
    "EDF0": { topic: "charge_current", scale: 10 },
    "EDF6": { topic: "float_voltage", scale: 100 },
    "EDF7": { topic: "absorption_voltage", scale: 100 },
    "0200": { topic: "device_mode", scale: 1 }
};

// buffer values
let buffer = context.get("buffer") || {
    V: [],
    I: [],
    VPV: [],
    PPV: [],
    MPPT: [],
    CS: [],
    ERR: [],
    H19: [],
    H20: [],
    H21: [],
    H22: [],
    H23: [],
    HSDS: []
};

function average(arr) {
    if (arr.length === 0) return 0;
    return arr.reduce((a,b)=>a+b,0)/arr.length;
}

for (let line of lines) {

    line = line.trim();

    if (line === "")
        continue;

    //------------------------------------------------
    // HEX FRAME
    //------------------------------------------------

    if (line.startsWith(":")) {

        switch(line[1]) {

            //----------------------------------------
            // GET RESPONSE
            //----------------------------------------
            case "7":

                let s = line.substring(1);

                let reg = s.substr(1,4);
                reg = reg.substr(2,2) + reg.substr(0,2);

                let cfg = REGISTERS[reg];

                if (reg === "0200") {

                    let value = parseInt(s.substr(7,2),16);

                    const deviceMode = {
                        1: "ON",
                        4: "OFF"
                    };

                    node.send({
                        topic: cfg.topic,
                        payload: deviceMode[value] || "UNKNOWN"
                    });

                } else {

                    let lsb = parseInt(s.substr(7,2),16);
                    let msb = parseInt(s.substr(9,2),16);

                    node.send({
                        topic: cfg.topic,
                        payload: ((msb << 8) | lsb) / cfg.scale
                    });
                }

                break;

            //----------------------------------------
            // SET ACK
            //----------------------------------------
            case "8":
                break;

            //----------------------------------------
            // ASYNC
            //----------------------------------------
            case "A":
                break;
        }

        continue;
    }

    //------------------------------------------------
    // ASCII VE.Direct
    //------------------------------------------------

    let parts = line.split("\t");

    if (parts.length < 2)
        continue;

    let key = parts[0].trim();
    let value = parseInt(parts[1]);

    switch(key) {

        case "V":
            buffer.V.push(value/1000.0);
            if(buffer.V.length>10) buffer.V.shift();
            node.send({topic:"battery_voltage",payload:Number(average(buffer.V).toFixed(2))});
            break;

        case "I":
            buffer.I.push(value/1000.0);
            if(buffer.I.length>10) buffer.I.shift();
            node.send({topic:"battery_current",payload:Number(average(buffer.I).toFixed(2))});
            break;

        case "VPV":
            buffer.VPV.push(value/1000.0);
            if(buffer.VPV.length>10) buffer.VPV.shift();
            node.send({topic:"pv_voltage",payload:Number(average(buffer.VPV).toFixed(2))});
            break;

        case "PPV":
            buffer.PPV.push(value);
            if(buffer.PPV.length>10) buffer.PPV.shift();
            node.send({topic:"pv_power",payload:Number(average(buffer.PPV).toFixed(0))});
            break;

        case "MPPT":
            const trackingMode = {
                0: "OFF",
                1: "Limited",
                2: "Active"
            };
            node.send({
                topic: "tracking_mode",
                payload: trackingMode[value] || "unknown"
            });
            break;

        case "CS":
            const chargeMode = {
                0: "OFF",
                2: "Fault",
                3: "Bulk",
                4: "Absorption",
                5: "Float"
            };
            node.send({
                topic: "charging_mode",
                payload: chargeMode[value] || "unknown"
            });
            break;

        case "ERR":
            node.send({topic:"error",payload:value});
            break;

        case "H19":
            node.send({topic:"yield_total",payload:value*10});
            break;

        case "H20":
            node.send({topic:"yield_today",payload:value*10});
            break;

        case "H21":
            node.send({topic:"maxPower_today",payload:value});
            break;

        case "H22":
            node.send({topic:"yield_yesterday",payload:value*10});
            break;

        case "H23":
            node.send({topic:"maxPower_yesterday",payload:value});
            break;

        case "HSDS":

            node.send({topic:"day_number",payload:value});

            let pvv = average(buffer.VPV);
            let pvp = average(buffer.PPV);

            if(pvv>0){
                node.send({
                    topic:"pv_current",
                    payload:Number((pvp/pvv).toFixed(2))
                });
            }

            break;
    }

}

context.set("buffer",buffer);

return null;

// msg.topic   = "set_charge_current"
// msg.payload = 0...70

// msg.topic   = "set_device_mode"
// msg.payload = 1-ON 4-OFF


const REGISTERS = {

    set_charge_current: {
        reg: 0xEDF0,
        min: 0,
        max: 70,
        scale: 10,
        bytes: 2
    },

    set_absorption_voltage: {
        reg: 0xEDF7,
        min: 50.0,
        max: 55.5,
        scale: 100,
        bytes: 2
    },

    set_float_voltage: {
        reg: 0xEDF6,
        min: 50.0,
        max: 55.5,
        scale: 100,
        bytes: 2
    },

    set_device_mode: {
        reg: 0x0200,
        values: [1, 4],
        scale: 1,
        bytes: 1
    }

};

let cfg = REGISTERS[msg.topic];

if (!cfg) {
    node.warn("Unknown topic: " + msg.topic);
    return null;
}

let value = Number(msg.payload);

if (isNaN(value))
    return null;

// valid
if (cfg.values) {

    if (!cfg.values.includes(value)) {
        node.warn("Invalid value: " + value);
        return null;
    }

} else {

    if (cfg.min !== undefined && value < cfg.min)
        value = cfg.min;

    if (cfg.max !== undefined && value > cfg.max)
        value = cfg.max;
}

// conversion
value = Math.round(value * cfg.scale);

// reg
let regL = cfg.reg & 0xFF;
let regH = (cfg.reg >> 8) & 0xFF;

// command
let cmd = 0x08;
let flags = 0x00;

let checksum;

function hexByte(v) {
    return v.toString(16).toUpperCase().padStart(2, "0");
}

function hexCmd(v) {
    return v.toString(16).toUpperCase();
}

//======================================================
// Reg 1 byte (Device Mode)
//======================================================

if (cfg.bytes === 1) {

    let sum =
        cmd +
        regL +
        regH +
        flags +
        value;

    checksum = (0x55 - (sum & 0xFF)) & 0xFF;

    msg.payload =
        ":" +
        hexCmd(cmd) +
        hexByte(regL) +
        hexByte(regH) +
        hexByte(flags) +
        hexByte(value) +
        hexByte(checksum) +
        "\n";

}
//======================================================
// Reg 2 bytes
//======================================================
else {

    let valL = value & 0xFF;
    let valH = (value >> 8) & 0xFF;

    let sum =
        cmd +
        regL +
        regH +
        flags +
        valL +
        valH;

    checksum = (0x55 - (sum & 0xFF)) & 0xFF;

    msg.payload =
        ":" +
        hexCmd(cmd) +
        hexByte(regL) +
        hexByte(regH) +
        hexByte(flags) +
        hexByte(valL) +
        hexByte(valH) +
        hexByte(checksum) +
        "\n";
}

return msg;

// msg.topic = "get_charge_current".....

const REGISTERS = {

    get_charge_current: {
        reg: 0xEDF0
    },

    get_absorption_voltage: {
        reg: 0xEDF7
    },

    get_float_voltage: {
        reg: 0xEDF6
    },

    get_device_mode: {
        reg: 0x0200
    }

};

let cfg = REGISTERS[msg.topic];

if (!cfg) {
    node.warn("Unknown topic: " + msg.topic);
    return null;
}

// little-endian reg
let regL = cfg.reg & 0xFF;
let regH = (cfg.reg >> 8) & 0xFF;

// GET frame
let cmd = 0x07;

// checksum
let checksum = (0x55 - ((cmd + regL + regH) & 0xFF)) & 0xFF;

function hex(v) {
    return v.toString(16).toUpperCase().padStart(2, "0");
}

msg.payload =
    ":\n"+ // line to init. mppt
    ":" +
    "7" +
    hex(regL) +
    hex(regH) +
    "00" +
    hex(checksum) +
    "\n";

return msg;
